-- Halls Head Cricket Club — PostgreSQL schema + seed data
-- Generated from the master workbook. Player IDs match the app's player register.
BEGIN;
DROP TABLE IF EXISTS season_aggregate_winners,career_stats,centuries,five_wicket_hauls,partnership_records,partnerships_50plus,
  premiership_players,honour_board,awards,grade_honours,life_members,team_of_decade,club_records,
  honour_board_records,seasons,players CASCADE;

CREATE TABLE players (
  player_id    INTEGER PRIMARY KEY,
  surname      TEXT,
  given        TEXT,
  full_name    TEXT,
  role         TEXT CHECK (role IN ('Batter','Bowler','All-rounder','Wicketkeeper','Club Official')),
  grades_played TEXT,
  total_games  INTEGER,
  in_app       BOOLEAN DEFAULT TRUE,
  notes        TEXT
);
CREATE TABLE seasons (season TEXT PRIMARY KEY);
CREATE TABLE career_stats (
  id SERIAL PRIMARY KEY,
  player_id INTEGER REFERENCES players(player_id),
  grade TEXT, surname TEXT, given TEXT, full_name TEXT,
  games INT, inns INT, no INT, runs INT, bat_ave NUMERIC, hs TEXT,
  fifties INT, hundreds INT, wkts INT, bowl_runs INT, bowl_ave NUMERIC, best_bowl TEXT,
  five_w INT, catch INT, stumpings INT, run_outs INT, stats_to TEXT, source_file TEXT
);
CREATE TABLE centuries (id SERIAL PRIMARY KEY, player_id INTEGER REFERENCES players(player_id), grade TEXT, batsman TEXT, score TEXT, season TEXT);
CREATE TABLE five_wicket_hauls (id SERIAL PRIMARY KEY, player_id INTEGER REFERENCES players(player_id), grade TEXT, bowler TEXT, figures TEXT, season TEXT);
CREATE TABLE partnership_records (id SERIAL PRIMARY KEY, grade TEXT, wicket TEXT, runs INT, batsmen TEXT, opposition TEXT, season TEXT);
CREATE TABLE partnerships_50plus (id SERIAL PRIMARY KEY, grade TEXT, wicket TEXT, runs INT, batsmen TEXT, opposition TEXT, season TEXT, source TEXT);
CREATE TABLE premiership_players (id SERIAL PRIMARY KEY, player_id INTEGER REFERENCES players(player_id), grade TEXT, season TEXT, player TEXT);
CREATE TABLE honour_board (id SERIAL PRIMARY KEY, season TEXT, role TEXT, person TEXT, player_id INTEGER REFERENCES players(player_id));
CREATE TABLE awards (id SERIAL PRIMARY KEY, season TEXT, award TEXT, recipient TEXT, player_id INTEGER REFERENCES players(player_id));
CREATE TABLE grade_honours (id SERIAL PRIMARY KEY, season TEXT, role TEXT, grade TEXT, person TEXT, player_id INTEGER REFERENCES players(player_id));
CREATE TABLE life_members (id SERIAL PRIMARY KEY, name TEXT, season_inducted TEXT, player_id INTEGER REFERENCES players(player_id));
CREATE TABLE team_of_decade (id SERIAL PRIMARY KEY, grade TEXT, position INT, player TEXT, note TEXT);
CREATE TABLE club_records (id SERIAL PRIMARY KEY, record_type TEXT, grade TEXT, detail TEXT);
CREATE TABLE honour_board_records (id SERIAL PRIMARY KEY, category TEXT, rank INT, name TEXT, value TEXT);
CREATE TABLE season_aggregate_winners (id SERIAL PRIMARY KEY, grade TEXT, season TEXT, category TEXT, player TEXT, player_id INTEGER REFERENCES players(player_id), figure INTEGER, average NUMERIC, raw TEXT);


-- players: 693 rows

-- seasons: 5 rows

-- career_stats: 1576 rows

-- centuries: 188 rows

-- five_wicket_hauls: 293 rows

-- partnership_records: 98 rows

-- partnerships_50plus: 246 rows

-- premiership_players: 472 rows

-- honour_board: 232 rows

-- awards: 113 rows

-- grade_honours: 305 rows

-- life_members: 14 rows

-- team_of_decade: 26 rows

-- club_records: 74 rows

-- honour_board_records: 30 rows

-- season_aggregate_winners: 561 rows

-- reset identity sequences
SELECT setval(pg_get_serial_sequence('career_stats','id'), COALESCE((SELECT MAX(id) FROM career_stats),1));
SELECT setval(pg_get_serial_sequence('centuries','id'), COALESCE((SELECT MAX(id) FROM centuries),1));
SELECT setval(pg_get_serial_sequence('five_wicket_hauls','id'), COALESCE((SELECT MAX(id) FROM five_wicket_hauls),1));
SELECT setval(pg_get_serial_sequence('partnership_records','id'), COALESCE((SELECT MAX(id) FROM partnership_records),1));
SELECT setval(pg_get_serial_sequence('partnerships_50plus','id'), COALESCE((SELECT MAX(id) FROM partnerships_50plus),1));
SELECT setval(pg_get_serial_sequence('premiership_players','id'), COALESCE((SELECT MAX(id) FROM premiership_players),1));
SELECT setval(pg_get_serial_sequence('honour_board','id'), COALESCE((SELECT MAX(id) FROM honour_board),1));
SELECT setval(pg_get_serial_sequence('awards','id'), COALESCE((SELECT MAX(id) FROM awards),1));
SELECT setval(pg_get_serial_sequence('grade_honours','id'), COALESCE((SELECT MAX(id) FROM grade_honours),1));
SELECT setval(pg_get_serial_sequence('life_members','id'), COALESCE((SELECT MAX(id) FROM life_members),1));
SELECT setval(pg_get_serial_sequence('team_of_decade','id'), COALESCE((SELECT MAX(id) FROM team_of_decade),1));
SELECT setval(pg_get_serial_sequence('club_records','id'), COALESCE((SELECT MAX(id) FROM club_records),1));
SELECT setval(pg_get_serial_sequence('honour_board_records','id'), COALESCE((SELECT MAX(id) FROM honour_board_records),1));
SELECT setval(pg_get_serial_sequence('season_aggregate_winners','id'), COALESCE((SELECT MAX(id) FROM season_aggregate_winners),1));

CREATE INDEX idx_career_player ON career_stats(player_id);
CREATE INDEX idx_career_grade ON career_stats(grade);
CREATE INDEX idx_cent_player ON centuries(player_id);
CREATE INDEX idx_hb_season ON honour_board(season);
COMMIT;
